    // Use a Map to store the counts of how many ways each sum can be formed.
    // Key: the sum x = a^3 + b^3
    // Value: the count of representations
    const sumCounts = new Map();

    // Determine the maximum value for b. Since a >= 1, b^3 < n.
    // We can iterate b up to the cube root of n.
    // Since n <= 10^9, the maximum b is 1000.

    // We iterate b starting from 1.
    for (let b = 1; ; b++) {
        const bCubed = b * b * b;

        // If the smallest possible sum (a=1, b) already exceeds n, we can stop.
        // However, we must check a=1 explicitly inside the loop condition if we want to break early.
        if (bCubed + 1 > n && b > 1) {
             // If b=1, bCubed=1. If n=1, loop condition handles it. If n>=2, b=1 continues.
             // If we reach here, even 1^3 + b^3 > n, so we break.
             break;
        }

        // Iterate a from 1 up to b (since we require a <= b)
        for (let a = 1; a <= b; a++) {
            const aCubed = a * a * a;
            const x = aCubed + bCubed;

            if (x > n) {
                // Since a is increasing, all subsequent sums for this b will also be > n.
                break;
            }

            // Count the representation
            const currentCount = sumCounts.get(x) || 0;
            sumCounts.set(x, currentCount + 1);
        }
    }

    // Collect all sums that appeared at least twice
    const goodIntegers = [];
    for (const [sum, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodIntegers.push(sum);
        }
    }

    // Return the results sorted in ascending order
    return goodIntegers.sort((a, b) => a - b);
