import scala.collection.mutable

def n(N: Long): Array[Long] = {
    // Map to store the counts of how many ways each sum x = a^3 + b^3 can be formed.
    // Key: the sum x (Long)
    // Value: the count of representations (Int)
    val sumCounts: mutable.Map[Long, Int] = mutable.Map()

    var b: Long = 1
    while (true) {
        val bCubed = b * b * b

        // If even the smallest possible sum (a=1) exceeds N, we stop iterating b.
        if (1L + bCubed > N) {
            break
        }

        var a: Long = 1
        while (a <= b) {
            val aCubed = a * a * a
            val x = aCubed + bCubed

            if (x > N) {
                // Since a is increasing, subsequent sums for this b will also exceed N.
                break
            }

            // Count the representation
            sumCounts(x) = sumCounts.getOrElse(x, 0) + 1

            a += 1
        }
        b += 1
    }

    // Collect all sums (keys) where the count is >= 2, sort them, and convert to Array[Long].
    val goodIntegers = sumCounts
        .filterValues(_ >= 2)
        .keys
        .toSeq
        .sorted
        .toArray

    goodIntegers
}

